"""A shopping cart with line items, quantity management, and discounting.

This module exposes the :class:`ShoppingCart` aggregate together with the value
objects and exceptions that make up its public contract. It contains no I/O and
prints nothing; every operation either mutates cart state or returns a value,
which keeps the type easy to test and to embed in a larger application.
"""

from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Iterable

__all__ = [
    "CartError",
    "ItemNotFoundError",
    "DuplicateItemError",
    "InvalidPriceError",
    "InvalidQuantityError",
    "InvalidDiscountError",
    "LineItem",
    "Discount",
    "PercentageDiscount",
    "FlatDiscount",
    "ShoppingCart",
]


# --------------------------------------------------------------------------- #
# Exceptions
# --------------------------------------------------------------------------- #
class CartError(Exception):
    """Base class for every error raised by this module.

    Catching :class:`CartError` lets callers handle all cart-related failures
    without also swallowing unrelated exceptions.
    """


class ItemNotFoundError(CartError):
    """Raised when an operation targets a product that is not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} is in the cart.")
        self.product_name = product_name


class DuplicateItemError(CartError):
    """Raised when adding a product that already exists as a line item."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item named {product_name!r} already exists; "
            f"update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidPriceError(CartError):
    """Raised when a unit price is negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative; got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(CartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer; got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(CartError):
    """Raised when a discount is configured with an out-of-range value."""

    def __init__(self, message: str) -> None:
        super().__init__(message)


# --------------------------------------------------------------------------- #
# Value objects
# --------------------------------------------------------------------------- #
@dataclass(frozen=True)
class LineItem:
    """An immutable snapshot of a single product line in the cart.

    Instances are validated on construction, so any ``LineItem`` you hold is
    guaranteed to have a non-negative ``unit_price`` and a positive ``quantity``.
    """

    product_name: str
    unit_price: Decimal
    quantity: int

    def __post_init__(self) -> None:
        if self.unit_price < Decimal("0"):
            raise InvalidPriceError(self.unit_price)
        if self.quantity <= 0:
            raise InvalidQuantityError(self.quantity)

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line: ``unit_price * quantity``."""
        return self.unit_price * self.quantity

    def with_quantity(self, quantity: int) -> "LineItem":
        """Return a copy of this line item with a new quantity."""
        return replace(self, quantity=quantity)


@dataclass(frozen=True)
class Discount:
    """Base class for discount strategies.

    A discount maps a subtotal to the (non-negative) amount to deduct from it.
    Subclasses implement :meth:`amount_for`; the cart treats them polymorphically,
    so new discount kinds can be added without changing :class:`ShoppingCart`.
    """

    def amount_for(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount applicable to ``subtotal``."""
        raise NotImplementedError


@dataclass(frozen=True)
class PercentageDiscount(Discount):
    """A discount expressed as a percentage of the subtotal (0–100)."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if not Decimal("0") <= self.percentage <= Decimal("100"):
            raise InvalidDiscountError(
                f"Percentage must be between 0 and 100; got {self.percentage}."
            )

    def amount_for(self, subtotal: Decimal) -> Decimal:
        return subtotal * self.percentage / Decimal("100")


@dataclass(frozen=True)
class FlatDiscount(Discount):
    """A fixed-amount discount, capped at the subtotal so totals never go negative."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < Decimal("0"):
            raise InvalidDiscountError(
                f"Flat discount must not be negative; got {self.amount}."
            )

    def amount_for(self, subtotal: Decimal) -> Decimal:
        return min(self.amount, subtotal)


# --------------------------------------------------------------------------- #
# Aggregate
# --------------------------------------------------------------------------- #
class ShoppingCart:
    """A collection of unique product lines that computes totals and discounts.

    Products are keyed by name, so each product appears at most once; call
    :meth:`update_quantity` to change how many of an existing product are in the
    cart. Monetary values use :class:`decimal.Decimal` to avoid binary
    floating-point rounding errors.
    """

    def __init__(self) -> None:
        self._items_by_name: dict[str, LineItem] = {}
        self._discount: Discount | None = None

    # ----- queries -------------------------------------------------------- #
    def list_items(self) -> tuple[LineItem, ...]:
        """Return all line items as an immutable, insertion-ordered tuple."""
        return tuple(self._items_by_name.values())

    def subtotal(self) -> Decimal:
        """Return the sum of every line total, before any discount is applied."""
        return sum(
            (item.line_total for item in self._items_by_name.values()),
            start=Decimal("0"),
        )

    def discount_amount(self) -> Decimal:
        """Return the currency amount removed by the active discount (0 if none)."""
        if self._discount is None:
            return Decimal("0")
        return self._discount.amount_for(self.subtotal())

    def total(self) -> Decimal:
        """Return the payable total: :meth:`subtotal` minus :meth:`discount_amount`."""
        return self.subtotal() - self.discount_amount()

    # ----- commands ------------------------------------------------------- #
    def add_item(
        self, product_name: str, unit_price: Decimal, quantity: int
    ) -> LineItem:
        """Add a new product line and return it.

        Raises:
            DuplicateItemError: If a line for ``product_name`` already exists.
            InvalidPriceError: If ``unit_price`` is negative.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        if product_name in self._items_by_name:
            raise DuplicateItemError(product_name)
        line_item = LineItem(product_name, unit_price, quantity)
        self._items_by_name[product_name] = line_item
        return line_item

    def remove_item(self, product_name: str) -> None:
        """Remove the line for ``product_name``.

        Raises:
            ItemNotFoundError: If no such product is in the cart.
        """
        self._require_item(product_name)
        del self._items_by_name[product_name]

    def update_quantity(self, product_name: str, quantity: int) -> LineItem:
        """Set the quantity of an existing product and return the updated line.

        Raises:
            ItemNotFoundError: If no such product is in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        updated_item = existing_item.with_quantity(quantity)
        self._items_by_name[product_name] = updated_item
        return updated_item

    def apply_discount(self, discount: Discount) -> None:
        """Set the discount applied to the subtotal, replacing any previous one."""
        self._discount = discount

    def clear_discount(self) -> None:
        """Remove the active discount, if any."""
        self._discount = None

    def clear(self) -> None:
        """Remove every item and discount, restoring the empty initial state."""
        self._items_by_name.clear()
        self._discount = None

    # ----- helpers -------------------------------------------------------- #
    def _require_item(self, product_name: str) -> LineItem:
        """Return the line for ``product_name`` or raise :class:`ItemNotFoundError`."""
        try:
            return self._items_by_name[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None

    # ----- dunder --------------------------------------------------------- #
    def __len__(self) -> int:
        """Return the number of distinct product lines in the cart."""
        return len(self._items_by_name)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product with the given name is in the cart."""
        return product_name in self._items_by_name

    def __iter__(self) -> Iterable[LineItem]:
        """Iterate over the cart's line items in insertion order."""
        return iter(self._items_by_name.values())
```

### Design notes

- **Data structure**: `LineItem` is a frozen `dataclass` that self-validates in `__post_init__`, so an invalid line can never exist. `line_total` is a derived property, keeping the data normalized (DRY — quantity × price lives in one place).
- **SRP**: Each method does exactly one thing. `total()` composes `subtotal()` and `discount_amount()` rather than recomputing anything.
- **Open/Closed + Strategy pattern**: `Discount` is an abstract strategy with `PercentageDiscount` / `FlatDiscount` subclasses. The cart depends only on the `Discount.amount_for` interface, so new discount types require zero changes to `ShoppingCart`.
- **DRY**: `_require_item` centralizes the "fetch or raise" lookup used by both `remove_item` and `update_quantity`.
- **Specific exceptions**: A `CartError` hierarchy with named, attribute-carrying exceptions instead of bare `ValueError`/`Exception`.
- **Correctness**: `Decimal` avoids float rounding bugs in money math; `FlatDiscount` caps at the subtotal so totals never go negative.
- **No mutable defaults, no prints**: State is initialized in `__init__`; every method returns values.

